fixed_code:
fn main() {
    let data = vec![1, 2, 3, 4];
    let (evens, odds): (Vec<_>, Vec<_>) = data.into_iter().partition(|x| *x % 2 == 0);
    println!("Evens: {:?}, Odds: {:?}", evens, odds);
}
